SELECT NIINGRED.NIEAN AS niean, NIINGRED.NILDESC AS nildesc, NIINGRED.NIBRAND AS nibrand, NIINGRED.NIINGREDS AS niingreds, NIINGRED.NIABV AS niabv, NIINGRED.NIMANUFNADD AS nimanufnadd, NIINGRED.NIORIGIN AS niorigin, NIINGRED.NISTORAGE AS nistorage, NIINGRED.NISTORAGETYPE AS nistoragetype, NIINGRED.NINUTRITIONHTML AS ninutritionhtml, NIINGRED.NIPREPUSAGE AS niprepusage, NIINGRED.NICOOKGUIDE AS nicookguide, NIINGRED.NICOOKCONCISE AS nicookconcise, CONCAT(CONCAT(CAST(NIINGRED.NINETWGT, CHAR(10)) WITH ' ') WITH NIINGRED.NIWGTUNIT) AS unit_net_weight INTO PRODUCTDESCLOOKUP FROM NIINGRED WHERE NIINGRED.NILDESC IS NOT NULL AND NIINGRED.NILANG = 'ENGLISH';
